#include <string.h>
#include <stdio.h>
#include <stdlib.h>
#include "resolver.h"

#define MAX_HOSTNAME 256

int parse_hostname(const char *input, char *host, int *port) {
    if (!input || strlen(input) >= MAX_HOSTNAME) {
        return -1;
    }
    char buf[MAX_HOSTNAME];
    snprintf(buf, sizeof(buf), "%s", input);
    char *colon = strchr(buf, ':');
    if (colon) {
        *colon = '\0';
        *port = atoi(colon + 1);
    } else {
        *port = 80;
    }
    strncpy(host, buf, MAX_HOSTNAME - 1);
    host[MAX_HOSTNAME - 1] = '\0';
    return 0;
}
